// src/memory/memory-log.ts
function eventFragmentWhy(fragment) {
  if (fragment.sources.length === 0)
    return null;
  const parts2 = fragment.sources.map((s) => {
    const ref = s.ref.length > 8 ? s.ref.slice(0, 8) : s.ref;
    return `${s.kind} ${ref}`;
  });
  return `from ${parts2.join(", ")}`;
}
function episodeWhy(episode) {
  const n = episode.member_fragment_ids.length;
  return `episode \xB7 ${n} events on ${episode.day_key}`;
}
function factStatus(status) {
  if (status === "active")
    return "active";
  if (status === "pending")
    return "pending";
  return "retired";
}
function buildMemoryLog(input2) {
  const semanticEvents = input2.facts.map((f) => ({
    ts: f.created_at,
    type: "semantic",
    text: f.text,
    why: f.save_reason,
    status: factStatus(f.status),
    id: f.id,
    recall_count: f.recall_count,
    last_confirmed_at: f.last_confirmed_at,
    events: f.events,
    supersedes: f.supersedes,
    superseded_by: f.superseded_by,
    stream: f.learned_from?.stream ?? null,
    kind: f.kind ?? null,
    entities: f.entities ?? null
  }));
  const episodicEvents = input2.critiques.filter((c) => !isRubricNoiseCritique(c.body)).map((c) => ({
    ts: c.ts,
    type: "episodic",
    text: c.body,
    why: c.reaction ?? null,
    status: "active",
    id: c.id,
    recall_count: 0,
    last_confirmed_at: null,
    events: [],
    supersedes: null,
    superseded_by: null,
    stream: null
  }));
  const eventFragmentEvents = (input2.eventFragments ?? []).map((f) => ({
    ts: f.occurred_at,
    type: "episodic",
    text: f.text,
    why: eventFragmentWhy(f),
    status: "active",
    id: f.id,
    recall_count: 0,
    last_confirmed_at: null,
    events: [],
    supersedes: null,
    superseded_by: null,
    stream: f.learned_from_stream,
    entities: f.entities
  }));
  const episodeEvents = (input2.episodes ?? []).map((ep) => ({
    ts: ep.time_span.end,
    type: "episodic",
    text: ep.narrative,
    why: episodeWhy(ep),
    status: "active",
    id: ep.id,
    recall_count: 0,
    last_confirmed_at: null,
    events: [],
    supersedes: null,
    superseded_by: null,
    stream: null,
    entities: ep.entity_labels.map((name2) => ({ name: name2 }))
  }));
  const proceduralEvents = input2.learnedRules.map((r) => ({
    ts: r.created_at,
    type: "procedural",
    text: r.text,
    why: r.source ?? null,
    status: "active",
    id: r.id,
    recall_count: 0,
    last_confirmed_at: null,
    events: [],
    supersedes: null,
    superseded_by: null,
    stream: null
  }));
  const all = [
    ...semanticEvents,
    ...episodicEvents,
    ...eventFragmentEvents,
    ...episodeEvents,
    ...proceduralEvents
  ];
  all.sort((a, b) => a.ts > b.ts ? -1 : a.ts < b.ts ? 1 : 0);
  return all;
}

// src/memory/memory-log-loader.ts
async function loadMemoryEvents(homeBase, deps) {
  const _readMemory = deps?.readMemory ?? readMemory;
  const _loadCritiques = deps?.loadCritiques ?? loadAllCritiqueEntries;
  const now = deps?.now ?? new Date;
  const [memory, critiqueEntries] = await Promise.all([
    _readMemory(homeBase),
    _loadCritiques(homeBase)
  ]);
  const facts = memory?.facts ?? [];
  const eventFragments = memory?.event_fragments ? activeEventFragments(memory, now) : [];
  const episodes = memory?.episodes ? activeEpisodes(memory, now) : [];
  const learnedRules = (memory?.learned_rules ?? []).map((r) => ({
    id: r.id,
    created_at: r.created_at,
    text: r.rule,
    source: r.source ?? r.category ?? null
  }));
  const critiques = critiqueEntries.map((entry) => ({
    id: entry.id,
    ts: entry.ts,
    body: entry.body,
    reaction: null
  }));
  return buildMemoryLog({ facts, critiques, learnedRules, eventFragments, episodes });
}

