// src/daemon/routes/chat-send-gate.ts
init_budget_config();
init_quiet_hours();
function evaluateChatSendGate(config2, rollup, quietConfig, now) {
  if (isQuietHour(now, quietConfig)) {
    return { blocked: "quiet_hours" };
  }
  const decision = evaluateBudget(rollup, config2);
  if (decision.stage === "hard") {
    return { blocked: "budget", used_pct: decision.used_pct };
  }
  return null;
}

// src/daemon/routes/repo-summary.ts
function mountRepoSummaryRoute(app, deps) {
  const home = deps.home;
  const callBrain2 = deps.callBrain ?? makeRoleRawBrain(home, "extract");
  const nowFn = deps.now ?? (() => new Date);
  app.post("/api/repo-summary", async (c) => {
    if (!isAuthorized(deps.secret, c.req.header("X-Siltpoke-Secret"))) {
      return c.json({ error: "unauthorized" }, 401);
    }
    let projectRoot = "";
    try {
      const body2 = await c.req.json();
      if (typeof body2.project_root === "string")
        projectRoot = body2.project_root;
    } catch {
      projectRoot = "";
    }
    if (projectRoot.length === 0) {
      return c.json({ error: "project_root is required" }, 400);
    }
    const storageDir = join53(home, "repo-memory", computeProjHash(projectRoot));
    const archModel = readJsonObject(join53(storageDir, "arch-model.json"));
    if (!archModel) {
      return c.json({ error: "repo has no architecture model \u2014 generate it first" }, 400);
    }
    const cached2 = readJsonObject(repoSummaryPath(home, projectRoot));
    if (cached2 && typeof cached2.text === "string" && cached2.text.trim().length > 0) {
      return c.json({ summary_text: cached2.text, cost_usd: 0, cached: true });
    }
    const now = nowFn();
    const budgetConfig = await loadBudgetConfig(home);
    const quietConfig = await loadQuietHoursConfig(home);
    const rollup = await loadDailyRollup(home, now, budgetConfig.resetAtMinutes);
    const gate = evaluateChatSendGate(budgetConfig, rollup, quietConfig, now);
    if (gate) {
      const reason = gate.blocked === "quiet_hours" ? "quiet hours \u2014 try again later" : "daily budget reached \u2014 try again tomorrow";
      return c.json({ error: reason, blocked: gate.blocked }, 429);
    }
    const fresh = readJsonObject(repoSummaryPath(home, projectRoot));
    if (fresh && typeof fresh.text === "string" && fresh.text.trim().length > 0) {
      return c.json({ summary_text: fresh.text, cost_usd: 0, cached: true });
    }
    let summaryText;
    let usage;
    try {
      const result = await callBrain2({
        systemPrompt: SUMMARY_SYSTEM_PROMPT,
        contextBundle: buildSummaryContext(archModel)
      });
      summaryText = parseSummaryOutput(result.output);
      usage = result.usage;
    } catch (err2) {
      return c.json({ error: `summary generation failed: ${err2 instanceof Error ? err2.message : String(err2)}` }, 502);
    }
    const brainConfig = await loadBrainConfig(home);
    const resolvedModel = resolveRoleMeta(brainConfig, "extract").model ?? "unknown";
    const costUsd = usage.total_cost_usd ?? 0;
    writeRepoSummary(home, projectRoot, {
      text: summaryText,
      model: resolvedModel,
      generated_ts: now.toISOString(),
      cost_usd: costUsd
    });
    await appendUsageEvent(home, {
      ts: now.toISOString(),
      kind: "repo_summary",
      session_id: `repo-summary:${computeProjHash(projectRoot)}`,
      input_tokens: usage.input_tokens ?? 0,
      output_tokens: usage.output_tokens ?? 0,
      cache_creation_input_tokens: usage.cache_creation_input_tokens ?? 0,
      cache_read_input_tokens: usage.cache_read_input_tokens ?? 0,
      total_cost_usd: usage.total_cost_usd,
      basis: "real"
    });
    return c.json({ summary_text: summaryText, cost_usd: costUsd, cached: false });
  });
}

