        const cap = (s) => s.length > 500 ? `${s.slice(0, 500)}\u2026` : s;
        const finishErrorMsg = outcome.kind === "malformed" ? `malformed: ${cap(outcome.message)} [output_tokens:${outcome.usage.output_tokens}]` : outcome.kind === "integrity_failed" ? `integrity_failed: ${cap(outcome.message)}` : outcome.kind === "cost_cap_exceeded" ? `cost_cap_exceeded: hard_cap=$${outcome.hardCapUsd} actual=$${outcome.costUsd}` : undefined;
