      span_id: this.genSpanId(),
      parent_span_id: opts.parent?.span_id ?? null,
      name: opts.name,
      kind: opts.kind,
      start_unix_nano: Date.now() * 1e6,
      end_unix_nano: 0,
      status: { code: "UNSET" },
      attributes: { ...opts.attributes ?? {} },
      events: []
