// src/cli/daemon-stop-guard.ts
async function checkActiveTask(baseUrl, fetchFn = fetch) {
  let res;
  try {
    res = await fetchFn(`${baseUrl}/api/repo-graph/arch/task`, {
      signal: AbortSignal.timeout(1500)
    });
  } catch {
    return { block: false };
  }
  if (!res.ok)
    return { block: false };
  let body2;
  try {
    body2 = await res.json();
  } catch {
    return { block: false };
  }
  if (typeof body2 !== "object" || body2 === null || body2.success !== true) {
    return { block: false };
  }
  const data = body2.data;
  if (!data || typeof data !== "object")
    return { block: false };
  const task = data.task;
  if (!task || typeof task !== "object")
    return { block: false };
  if (task.status !== "running")
    return { block: false };
  const id = task.id;
  const kind = task.kind;
  const repo = task.repo;
  const startedTs = task.startedTs;
  if (!id || !kind || !repo || !startedTs)
    return { block: false };
  const startedAgoMs = Date.now() - new Date(startedTs).getTime();
  if (!Number.isFinite(startedAgoMs))
    return { block: false };
  return {
    block: true,
    task: { id, kind, repo, status: "running", startedTs, startedAgoMs }
  };
}
async function runStopWithGuard(opts) {
  const { pid, force, baseUrl, kill, stderr, stdout } = opts;
  const fetchFn = opts.fetchFn ?? fetch;
  if (!force) {
    const check2 = await checkActiveTask(baseUrl, fetchFn);
    if (check2.block) {
      const t = check2.task;
      const ago = formatAgo(t.startedAgoMs);
      stderr(`siltpoked: a paid arch-generate is running (repo=${t.repo}, kind=${t.kind}, started ${ago}).
` + `Stopping now will SIGKILL the run \u2014 it will be ledgered as a failed estimate.
` + `Use  siltpoked stop --force  to stop anyway.
`);
      return 1;
    }
  }
  try {
    kill(pid, "SIGTERM");
    stdout(`Sent SIGTERM to pid=${pid}
`);
    return 0;
  } catch (err2) {
    stderr(`siltpoked: failed to kill pid=${pid}: ${err2.message}
`);
    return 1;
  }
}
function formatAgo(ms) {
  const s = Math.round(ms / 1000);
  if (s < 60)
    return `${s}s ago`;
  const m = Math.floor(s / 60);
  const rem = s % 60;
  return rem > 0 ? `${m}m ${rem}s ago` : `${m}m ago`;
}

// src/installer/autostart.ts
async function dispatch(moduleName, platform, load, home) {
  const mod = await load();
  if (!mod || typeof mod.installAutostart !== "function") {
    return { status: "unavailable", platform, module: moduleName };
  }
  await mod.installAutostart(home);
  return { status: "installed", platform };
}
async function installAutostartForPlatform(opts = {}) {
  const platform = opts.platform ?? process.platform;
  if (platform === "darwin") {
    const load = opts.loadLaunchd ?? (() => Promise.resolve().then(() => (init_launchd(), exports_launchd)).catch(() => null));
    return dispatch("launchd", platform, load, opts.home);
  }
  if (platform === "linux") {
    const load = opts.loadSystemd ?? (() => Promise.resolve().then(() => (init_systemd(), exports_systemd)).catch(() => null));
    return dispatch("systemd", platform, load, opts.home);
  }
  return { status: "skipped", platform };
}

// src/cli/daemon-restart.ts
