var sub = process.argv[2] ?? "status";
var detach = process.argv.includes("--detach");
var force = process.argv.includes("--force");
switch (sub) {
  case "start":
    await cmdStart(detach);
    break;
  case "stop":
    await cmdStop(force);
    break;
  case "status":
    cmdStatus();
    break;
  case "restart":
    process.exit(runRestart());
    break;
  case "install-autostart":
    await cmdInstallAutostart();
    break;
  default:
    process.stderr.write(`unknown subcommand: ${sub}
usage: siltpoked [start|stop|status|restart|install-autostart] [--detach] [--force]
`);
    process.exit(2);
}
